// Merge Kite API responses into a data_snapshot inbound-event.
// Three parallel branches: positions, holdings, margins.
// The Hub routes data_snapshot → analyst model for numerical reasoning.

const items = $input.all();

let positions = { net: [], day: [] };
let holdings = [];
let margins = {};
let kiteErrors = [];

for (const item of items) {
  const j = item.json;

  if (j.status === 'error') {
    kiteErrors.push({ source: 'kite', message: j.message, code: j.error_type });
    continue;
  }

  // Kite API wraps responses: { status: 'success', data: {...} }
  const data = j.data || j;

  // Positions response has 'net' and 'day' arrays
  if (data.net !== undefined || data.day !== undefined) {
    positions = {
      net: (data.net || []).map(p => ({
        symbol: p.tradingsymbol,
        quantity: p.quantity,
        product: p.product,
        avg_price: p.average_price,
        last_price: p.last_price,
        pnl: p.pnl,
        unrealised: p.unrealised,
        realised: p.realised,
        buy_qty: p.buy_quantity,
        sell_qty: p.sell_quantity
      })),
      day: (data.day || []).map(p => ({
        symbol: p.tradingsymbol,
        quantity: p.quantity,
        product: p.product,
        avg_price: p.average_price,
        last_price: p.last_price,
        pnl: p.pnl,
        unrealised: p.unrealised,
        realised: p.realised,
        buy_qty: p.buy_quantity,
        sell_qty: p.sell_quantity
      }))
    };
    continue;
  }

  // Holdings: array of long-term holdings
  if (Array.isArray(data)) {
    holdings = data.map(h => ({
      symbol: h.tradingsymbol,
      quantity: h.quantity,
      product: h.product,
      avg_price: h.average_price,
      last_price: h.last_price,
      pnl: h.pnl,
      unrealised: h.unrealised
    }));
    continue;
  }

  // Margins: equity, commodity segments
  if (data.equity || data.commodity) {
    margins = {
      equity: data.equity ? {
        enabled: data.equity.enabled,
        net: data.equity.net,
        available: {
          cash: data.equity.available ? data.equity.available.cash : 0,
          intraday_payin: data.equity.available ? data.equity.available.intraday_payin : 0,
          delivery_margin: data.equity.available ? data.equity.available.delivery_margin : 0
        },
        utilised: {
          debits: data.equity.utilised ? data.equity.utilised.debits : 0,
          exposure: data.equity.utilised ? data.equity.utilised.exposure : 0,
          spans: data.equity.utilised ? data.equity.utilised.spans : 0,
          option_premium: data.equity.utilised ? data.equity.utilised.option_premium : 0
        }
      } : null,
      commodity: data.commodity ? {
        enabled: data.commodity.enabled,
        net: data.commodity.net,
        available: data.commodity.available || {},
        utilised: data.commodity.utilised || {}
      } : null
    };
    continue;
  }
}

const totalPnL = [
  ...positions.net.map(p => p.pnl || 0),
  ...positions.day.map(p => p.pnl || 0),
  ...holdings.map(h => h.pnl || 0)
].reduce((a, b) => a + b, 0);

const dataPayload = {
  positions,
  holdings,
  margins,
  summary: {
    total_pnl: totalPnL,
    open_positions: positions.net.length + positions.day.length,
    holdings_count: holdings.length,
    equity_available: margins.equity ? margins.equity.available.cash : null
  },
  errors: kiteErrors.length > 0 ? kiteErrors : null,
  snapshot_time: new Date().toISOString()
};

const correlationId = crypto.randomUUID();

return [{
  json: {
    schema_version: '1.0',
    event_id: crypto.randomUUID(),
    correlation_id: correlationId,
    source: 'kite',
    type: 'data_snapshot',
    occurred_at: new Date().toISOString(),
    text: 'Portfolio snapshot: analyze positions, P&L, margin utilisation. Flag any unusual exposure concentration, stop-loss breaches, or margin nearing limits.',
    data: dataPayload,
    attachments: [],
    metadata: {
      trigger: 'scheduled',
      poll_interval_minutes: 15,
      exchange: 'NSE/BSE'
    }
  }
}];

// This spoke is INPUT only — data_snapshot flows through the Hub.
// To deliver results to you, chain an output spoke:
//   1. Connect the Route node's alpha/gamma output to an Execute Workflow node
//      pointing at slack-inbound / telegram-inbound / whatsapp-inbound (output mode).
//   2. Those spokes will deliver the ai_reply_text to your channel.
//
// For now, results go to the DB only (Hub handles that).
return $input.all();
